module top_module(
    A,
    B,
    S,
    Y
);input A, B, S;
    output Y;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire inv_not_S;

    // Invert S to generate inv_not_S
    assign inv_not_S = ~S;

    // Multiplexing operation
    assign Y = (inv_not_S & A) | (S & B);

endmodule
